  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — poke spirit stacks and hop his Heroic Swing engage.","breakdown":"Akshan plays around Heroic Swing. Q-E weave builds the passive drain, save the hop for his Heroic Swing, and the R slow-zone wins every committed fight. Doran’s Shield blunts the poke war.","dos":["Stack passive with Q-E","Hop windows beat his Heroic Swing","R zone the all-in"],"donts":["Burn E hop early","Poke without passive stacks","R defensively for nothing"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Spirit-stack burst + hop out."},"win":"Poke spirit stacks and hop his Heroic Swing engage."},
